/**
 * @summary Search items by keyword within a household
 */
export const getSearchItemsUrl = (params: SearchItemsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/items/search?${stringifiedParams}`
    : `/api/v1/items/search`;
};

export const searchItems = async (
  params: SearchItemsParams,
  options?: RequestInit,
): Promise<Item[]> => {
  return customFetch<Item[]>(getSearchItemsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchItemsQueryKey = (params?: SearchItemsParams) => {
  return [`/api/v1/items/search`, ...(params ? [params] : [])] as const;
};

export const getSearchItemsQueryOptions = <
  TData = Awaited<ReturnType<typeof searchItems>>,
  TError = ErrorType<unknown>,
>(
  params: SearchItemsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchItems>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getSearchItemsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof searchItems>>> = ({
    signal,
  }) => searchItems(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof searchItems>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

